fun main() {
    // ---- Function as parameter ----
    fun execute(action: () -> Unit) {
        println("Starting...")
        action()
        println("Done.")
    }

    execute {
        println("Performing action")
    }

    // ---- Function returning function ----
    fun createLogger(prefix: String): (String) -> Unit {
        return { message ->
            println("[$prefix] $message")
        }
    }

    val infoLogger = createLogger("INFO")
    val errorLogger = createLogger("ERROR")

    infoLogger("Application started")
    errorLogger("Something went wrong")

    // ---- Function with multiple parameters ----
    fun repeat(times: Int, action: (Int) -> Unit) {
        for (i in 1..times) {
            action(i)
        }
    }

    repeat(3) { i ->
        println("Iteration $i")
    }

    // ---- Function with receiver ----
    fun buildString(block: StringBuilder.() -> Unit): String {
        val sb = StringBuilder()
        sb.block()
        return sb.toString()
    }

    val result = buildString {
        append("Hello, ")
        append("World!")
    }
    println(result)

    // ---- Function composition ----
    fun compose(f: (Int) -> Int, g: (Int) -> Int): (Int) -> Int {
        return { f(g(it)) }
    }

    val double = { x: Int -> x * 2 }
    val addThree = { x: Int -> x + 3 }
    val doubleThenAddThree = compose(addThree, double)

    println("doubleThenAddThree(5) = ${doubleThenAddThree(5)}")

    // ---- Using built-in higher-order functions ----
    val numbers = listOf(1, 2, 3, 4, 5, 6)

    val even = numbers.filter { it % 2 == 0 }
    println("Even numbers: $even")

    val doubled = numbers.map { it * 2 }
    println("Doubled: $doubled")

    val sum = numbers.reduce { acc, i -> acc + i }
    println("Sum: $sum")

    val firstEven = numbers.find { it % 2 == 0 }
    println("First even: $firstEven")

    val allEven = numbers.all { it % 2 == 0 }
    println("All even? $allEven")

    // ---- Custom higher-order function ----
    fun <T, R> transform(list: List<T>, transformer: (T) -> R): List<R> {
        return list.map { transformer(it) }
    }

    val strings = listOf("Hello", "World", "Kotlin")
    val lengths = transform(strings) { it.length }
    println("String lengths: $lengths")
}

