phase3.solution:
fun filterNumbers(numbers: List<Int>, predicate: (Int) -> Boolean): List<Int> {
    return numbers.filter(predicate)
}

fun compose(f: (Int) -> Int, g: (Int) -> Int): (Int) -> Int {
    return { f(g(it)) }
}

fun main() {
    val numbers = listOf(1, 2, 3, 4, 5)

    val evens = filterNumbers(numbers) { it % 2 == 0 }
    println("Evens: $evens")

    val greaterThanThree = filterNumbers(numbers) { it > 3 }
    println("Greater than 3: $greaterThanThree")

    val double = { x: Int -> x * 2 }
    val addOne = { x: Int -> x + 1 }
    val doubleThenAddOne = compose(addOne, double)
    println("doubleThenAddOne(3) = ${doubleThenAddOne(3)}")
}
